fn sum_even_squares(numbers: &Vec<i32>) -> i32 {
    let mut result = 0;
    let mut i = 0;
    while i < numbers.len() {
        if numbers[i] % 2 == 0 {
            result += numbers[i] * numbers[i];
        }
        i += 1;
    }
    result
}

idiomaticSolution:
fn sum_even_squares(numbers: &[i32]) -> i32 {
    numbers.iter()
        .filter(|&&n| n % 2 == 0)
        .map(|&n| n * n)
        .sum()
}
